#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100
#define MAX_M 100

int main() {
    int T, N, M, Ai, Bi, Ci;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int **graph = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                graph[i][j] = INT_MAX;
            }
        }
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &Ai, &Bi, &Ci);
            graph[Ai - 1][Bi - 1] = Ci;
            graph[Bi - 1][Ai - 1] = Ci;
        }
        int *distance = (int *)malloc(N * sizeof(int));
        int *count = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            distance[i] = INT_MAX;
            count[i] = 0;
        }
        distance[0] = 0;
        count[0] = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    if (graph[j][k] != INT_MAX && distance[j] + graph[j][k] < distance[k]) {
                        distance[k] = distance[j] + graph[j][k];
                        count[k] = count[j];
                    } else if (graph[j][k] != INT_MAX && distance[j] + graph[j][k] == distance[k]) {
                        count[k] += count[j];
                    }
                }
            }
        }
        printf("%d\n", count[N - 1]);
        for (int i = 0; i < N; i++) {
            free(graph[i]);
        }
        free(graph);
        free(distance);
        free(count);
    }
    return 0;
}

