                graph[Ai][Bi] = Ci;
                graph[Bi][Ai] = Ci;
            }
            int[] distance = new int[N];
            int[] count = new int[N];
            for (int i = 0; i < N; i++) {
                distance[i] = Integer.MAX_VALUE;
